var dbgstr = {};

dbgstr.s_strDbgStrVS = `
    attribute vec4 a_Vertex;
    attribute vec2 a_UV;
    uniform   vec4 u_Translate;
    uniform   vec4 u_PrjMul, u_PrjAdd;
    varying   vec2 v_UV;

    void main()
    {
       vec4 pos;
       pos         = a_Vertex + u_Translate;
       pos         = pos * u_PrjMul;
       gl_Position = pos + u_PrjAdd;
       v_UV        = a_UV;
    }
`;

dbgstr.s_strDbgStrFS = `
    precision mediump float;

    varying vec2       v_UV;
    uniform sampler2D  u_Sampler0;
    uniform vec4       u_ColorFG;
    uniform vec4       u_ColorBG;

    void main()
    {
       vec4 texcol = texture2D (u_Sampler0, v_UV);
       gl_FragColor = mix (u_ColorBG, u_ColorFG, texcol.r);
    }
`;

const DEBSTR_FONT_WIDTH   = 12
const DEBSTR_FONT_HEIGHT  = 22
const DEBSTR_FONT_NUM     = 95
const DBGSTR_IMAGE_WIDTH  = DEBSTR_FONT_WIDTH*DEBSTR_FONT_NUM
const DBGSTR_IMAGE_HEIGHT = DEBSTR_FONT_HEIGHT

dbgstr.load_debug_font_texture = function (gl)
{
    let texid = gl.createTexture();
    gl.bindTexture (gl.TEXTURE_2D, texid);
    gl.texParameteri (gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR      );
    gl.texParameteri (gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR      );
    gl.texParameteri (gl.TEXTURE_2D, gl.TEXTURE_WRAP_S,     gl.CLAMP_TO_EDGE);
    gl.texParameteri (gl.TEXTURE_2D, gl.TEXTURE_WRAP_T,     gl.CLAMP_TO_EDGE);

    gl.pixelStorei (gl.UNPACK_ALIGNMENT, 4);

    gl.texImage2D (gl.TEXTURE_2D, 0, gl.LUMINANCE, 
                   DBGSTR_IMAGE_WIDTH, DBGSTR_IMAGE_HEIGHT,
                   0, gl.LUMINANCE, 
                   gl.UNSIGNED_BYTE,
                   new Uint8Array (dbgstr.s_font12x22.buffer));
    
    dbgstr.s_fontTexID = texid;
}


dbgstr.setup_shader = function (gl)
{
    sobj = GLUtil.generate_shader (gl, dbgstr.s_strDbgStrVS, dbgstr.s_strDbgStrFS);

    dbgstr.locVtx = gl.getAttribLocation (sobj.program, "a_Vertex");
    dbgstr.locUv  = gl.getAttribLocation (sobj.program, "a_UV"    );

    dbgstr.locSampler0  = gl.getUniformLocation (sobj.program, "u_Sampler0" );
    dbgstr.locTranslate = gl.getUniformLocation (sobj.program, "u_Translate");
    dbgstr.locPrjMul    = gl.getUniformLocation (sobj.program, "u_PrjMul");
    dbgstr.locPrjAdd    = gl.getUniformLocation (sobj.program, "u_PrjAdd");
    dbgstr.locColFG     = gl.getUniformLocation (sobj.program, "u_ColorFG" );
    dbgstr.locColBG     = gl.getUniformLocation (sobj.program, "u_ColorBG" );
    dbgstr.sobj = sobj;
}


function init_dbgstr (gl, win_w, win_h)
{
    dbgstr.s_wndW = win_w;
    dbgstr.s_wndH = win_h;

    dbgstr.load_debug_font_texture (gl);
    dbgstr.setup_shader (gl);

    dbgstr.vbo_vtx = gl.createBuffer();
    dbgstr.vbo_uv  = gl.createBuffer();
}

dbgstr.resize_viewport = function (gl, win_w, win_h)
{
    dbgstr.s_wndW = win_w;
    dbgstr.s_wndH = win_h;
}

dbgstr.draw_dbgstr_ex = function (gl, str, x, y, scale, col_fg, col_bg)
{
    let i, row, column;
    let u0, u1;
    let vertices = new Array(8);
    let texcoord = new Array(8);
    let fW = DEBSTR_FONT_WIDTH  * scale;
    let fH = DEBSTR_FONT_HEIGHT * scale;
    let fx = x;
    let fy = y;

    vertices[ 2 * 0 + 0 ] = fx;      vertices[ 2 * 0 + 1 ] = fy;
    vertices[ 2 * 1 + 0 ] = fx;      vertices[ 2 * 1 + 1 ] = fy + fH;
    vertices[ 2 * 2 + 0 ] = fx + fW; vertices[ 2 * 2 + 1 ] = fy;
    vertices[ 2 * 3 + 0 ] = fx + fW; vertices[ 2 * 3 + 1 ] = fy + fH;

    gl.useProgram (dbgstr.sobj.program);

    gl.bindBuffer (gl.ARRAY_BUFFER, dbgstr.vbo_vtx);
    gl.bufferData (gl.ARRAY_BUFFER, new Float32Array(vertices), gl.STATIC_DRAW);

    gl.enableVertexAttribArray (dbgstr.locVtx);
    gl.enableVertexAttribArray (dbgstr.locUv );
    gl.vertexAttribPointer (dbgstr.locVtx, 2, gl.FLOAT, false, 0, 0);

    gl.uniform1i (dbgstr.locSampler0, 0);
    gl.uniform4f (dbgstr.locPrjMul, 2.0 / dbgstr.s_wndW, -2.0 / dbgstr.s_wndH, 0.0, 0.0);
    gl.uniform4f (dbgstr.locPrjAdd, -1.0, 1.0, 1.0, 1.0);
    gl.uniform4fv (dbgstr.locColFG, col_fg);
    gl.uniform4fv (dbgstr.locColBG, col_bg);

    gl.disable (gl.DEPTH_TEST);
    gl.disable (gl.CULL_FACE );
    gl.activeTexture (gl.TEXTURE0);
    gl.bindTexture   (gl.TEXTURE_2D, dbgstr.s_fontTexID);

    gl.enable (gl.BLEND);
    gl.blendFuncSeparate (gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA, 
    	       gl.ONE, gl.ONE_MINUS_SRC_ALPHA);

    row = column = 0;
    for (i = 0; i < str.length; i ++)
    {
        let c = str.charCodeAt(i);

        if ( c == 0 )
            break;

        if (c == "\n".charCodeAt(0))
        {
            row ++;
            column = 0;
            continue;
        }

        u0 = (c - 0x20) * (1.0 / DEBSTR_FONT_NUM);
        u1 = u0 + (1.0 / DEBSTR_FONT_NUM);

        texcoord[ 2 * 0 + 0 ] = texcoord[ 2 * 1 + 0 ] = u0;
        texcoord[ 2 * 2 + 0 ] = texcoord[ 2 * 3 + 0 ] = u1;
        texcoord[ 2 * 0 + 1 ] = texcoord[ 2 * 2 + 1 ] = 0.0;
        texcoord[ 2 * 1 + 1 ] = texcoord[ 2 * 3 + 1 ] = 1.0;

        gl.uniform4f (dbgstr.locTranslate, column * fW, row * fH, 0.0, 0.0);

        gl.bindBuffer (gl.ARRAY_BUFFER, dbgstr.vbo_uv);
        gl.bufferData (gl.ARRAY_BUFFER, new Float32Array(texcoord), gl.STATIC_DRAW);
        gl.vertexAttribPointer (dbgstr.locUv, 2, gl.FLOAT, false, 0, 0);

        gl.drawArrays (gl.TRIANGLE_STRIP, 0, 4);

        column ++;
    }

    gl.disable (gl.BLEND);
    gl.disableVertexAttribArray (dbgstr.locVtx);
    gl.disableVertexAttribArray (dbgstr.locUv );

    return 0;
}


dbgstr.draw_dbgstr = function (gl, str, x, y)
{
    const col_fg = [1.0, 1.0, 1.0, 1.0];
    const col_bg = [0.0, 0.0, 0.0, 0.5];
    const scale = 1.0;

    dbgstr.draw_dbgstr_ex (gl, str, x, y, scale, col_fg, col_bg);
}


